import { createStore } from 'vuex'

export default createStore({
  state: {
    isFirstVisit: true
  },
  getters: {
    getIsFirstVisit: state => state.isFirstVisit
  },
  mutations: {
    SET_FIRST_VISIT (state, payload) {
      state.isFirstVisit = false
    }
  },
  actions: {
    isFirstVisit (context, payload) {
      if (context.getters.getIsFirstVisit) {
        context.commit('SET_FIRST_VISIT')
      } else {
        return false
      }
    }
  },
  modules: {
  }
})
